const e=JSON.parse('{"key":"v-3f000624","path":"/study/%E8%AE%BE%E8%AE%A1%E6%A8%A1%E5%BC%8F/15.%E5%91%BD%E4%BB%A4%E6%A8%A1%E5%BC%8F.html","title":"组合模式","lang":"zh-CN","frontmatter":{"title":"组合模式","icon":"sheji","order":15,"date":"2024-05-31T00:00:00.000Z","category":["设计模式"],"tag":["组合模式"],"description":"有时候需要向某些对象发送请求，但是并不知道请求的接收者是谁，也不知道被请求的操作是什么。需要一种松耦合的方式来设计程序，使得发送者和接收者能够消除彼此之间的耦合关系 命令模式由三种角色构成： 发布者invoker(发出命令，调用命令对象，不知道如何执行与谁执行) 接收者receiver(提供对应接口处理请求，不知道谁发起请求) 命令对象command(接收命令，调用接收者对应接口处理发布者的请求)","head":[["meta",{"property":"og:url","content":"https://luotianxu1.github.io/study/%E8%AE%BE%E8%AE%A1%E6%A8%A1%E5%BC%8F/15.%E5%91%BD%E4%BB%A4%E6%A8%A1%E5%BC%8F.html"}],["meta",{"property":"og:title","content":"组合模式"}],["meta",{"property":"og:description","content":"有时候需要向某些对象发送请求，但是并不知道请求的接收者是谁，也不知道被请求的操作是什么。需要一种松耦合的方式来设计程序，使得发送者和接收者能够消除彼此之间的耦合关系 命令模式由三种角色构成： 发布者invoker(发出命令，调用命令对象，不知道如何执行与谁执行) 接收者receiver(提供对应接口处理请求，不知道谁发起请求) 命令对象command(接收命令，调用接收者对应接口处理发布者的请求)"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2024-06-03T08:52:07.000Z"}],["meta",{"property":"article:author","content":"罗天旭"}],["meta",{"property":"article:tag","content":"组合模式"}],["meta",{"property":"article:published_time","content":"2024-05-31T00:00:00.000Z"}],["meta",{"property":"article:modified_time","content":"2024-06-03T08:52:07.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"组合模式\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2024-05-31T00:00:00.000Z\\",\\"dateModified\\":\\"2024-06-03T08:52:07.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"罗天旭\\",\\"url\\":\\"https://luotianxu1.github.io\\",\\"email\\":\\"1265062404@qq.com\\"}]}"]]},"headers":[],"git":{"createdTime":1717404412000,"updatedTime":1717404727000,"contributors":[{"name":"罗天旭","email":"ltx15122061897@163.com","commits":2}]},"readingTime":{"minutes":0.81,"words":242},"filePathRelative":"study/设计模式/15.命令模式.md","localizedDate":"2024年5月31日","excerpt":"<ul>\\n<li>\\n<p>有时候需要向某些对象发送请求，但是并不知道请求的接收者是谁，也不知道被请求的操作是什么。需要一种松耦合的方式来设计程序，使得发送者和接收者能够消除彼此之间的耦合关系</p>\\n</li>\\n<li>\\n<p>命令模式由三种角色构成：</p>\\n<ul>\\n<li>发布者<code>invoker</code>(发出命令，调用命令对象，不知道如何执行与谁执行)</li>\\n<li>接收者<code>receiver</code>(提供对应接口处理请求，不知道谁发起请求)</li>\\n<li>命令对象<code>command</code>(接收命令，调用接收者对应接口处理发布者的请求)</li>\\n</ul>\\n</li>\\n</ul>","autoDesc":true}');export{e as data};
